"""
Handlers for Content-Encoding.

See: https://developer.mozilla.org/en-US/docs/Web/HTTP/Headers/Content-Encoding
"""
import codecs
import io
import typing
import zlib

from ._compat import brotli
from ._exceptions import DecodingError


class ContentDecoder:
    def decode(self, data: bytes) -> bytes:
        """Decode a chunk of bytes and return the decoded bytes.

        Subclasses should implement this to process a chunk of incoming data.
        """
        raise NotImplementedError()  # pragma: no cover

    def flush(self) -> bytes:
        """Flush any buffered data and return the remaining decoded bytes.

        Subclasses should implement this to return any final data after all
        input chunks have been provided.
        """
        raise NotImplementedError()  # pragma: no cover


class IdentityDecoder(ContentDecoder):
    """
    Handle unencoded data.
    """

    def decode(self, data: bytes) -> bytes:
        """Return the input data unchanged for identity encoding."""
        return data

    def flush(self) -> bytes:
        """Nothing to flush for identity encoding."""
        return b""


class DeflateDecoder(ContentDecoder):
    """
    Handle 'deflate' decoding.

    See: https://stackoverflow.com/questions/1838699
    """

    def __init__(self) -> None:
        """Initialize a zlib decompressor for deflate data.

        Keeps track of whether this is the first attempt to try alternative
        window bits if needed.
        """
        self.first_attempt = True
        self.decompressor = zlib.decompressobj()

    def decode(self, data: bytes) -> bytes:
        """Decompress a chunk of deflate-compressed data, trying both zlib and
        raw deflate formats on the first attempt.
        """
        was_first_attempt = self.first_attempt
        self.first_attempt = False
        try:
            return self.decompressor.decompress(data)
        except zlib.error as exc:
            if was_first_attempt:
                # Some servers send raw deflate streams without zlib headers.
                self.decompressor = zlib.decompressobj(-zlib.MAX_WBITS)
                return self.decode(data)
            raise DecodingError(str(exc)) from exc

    def flush(self) -> bytes:
        """Flush the zlib decompressor and return any remaining decompressed bytes."""
        try:
            return self.decompressor.flush()
        except zlib.error as exc:  # pragma: no cover
            raise DecodingError(str(exc)) from exc


class GZipDecoder(ContentDecoder):
    """
    Handle 'gzip' decoding.

    See: https://stackoverflow.com/questions/1838699
    """

    def __init__(self) -> None:
        """Initialize a zlib decompressor configured for gzip format."""
        self.decompressor = zlib.decompressobj(zlib.MAX_WBITS | 16)

    def decode(self, data: bytes) -> bytes:
        """Decompress a chunk of gzip-compressed data."""
        try:
            return self.decompressor.decompress(data)
        except zlib.error as exc:
            raise DecodingError(str(exc)) from exc

    def flush(self) -> bytes:
        """Flush the gzip decompressor and return any remaining decompressed bytes."""
        try:
            return self.decompressor.flush()
        except zlib.error as exc:  # pragma: no cover
            raise DecodingError(str(exc)) from exc


class BrotliDecoder(ContentDecoder):
    """
    Handle 'brotli' decoding.

    Requires `pip install brotlipy`. See: https://brotlipy.readthedocs.io/
        or   `pip install brotli`. See https://github.com/google/brotli
    Supports both 'brotlipy' and 'Brotli' packages since they share an import
    name. The top branches are for 'brotlicffi' and bottom branches for 'Brotli'
    """

    def __init__(self) -> None:
        """Initialize a Brotli decompressor.

        Raises ImportError if no supported brotli implementation is installed.
        """
        if brotli is None:  # pragma: no cover
            raise ImportError(
                "Using 'BrotliDecoder', but neither of the 'brotlicffi' or 'brotli' "
                "packages have been installed. "
                "Make sure to install httpx using `pip install httpx[brotli]`."
            ) from None

        self.decompressor = brotli.Decompressor()
        self.seen_data = False
        self._decompress: typing.Callable[[bytes], bytes]
        if hasattr(self.decompressor, "decompress"):
            # The 'brotlicffi' package.
            self._decompress = self.decompressor.decompress  # pragma: no cover
        else:
            # The 'brotli' package.
            self._decompress = self.decompressor.process  # pragma: no cover

    def decode(self, data: bytes) -> bytes:
        """Decompress a chunk of brotli-compressed data."""
        if not data:
            return b""
        self.seen_data = True
        try:
            return self._decompress(data)
        except brotli.error as exc:
            raise DecodingError(str(exc)) from exc

    def flush(self) -> bytes:
        """Flush the brotli decompressor and return any remaining decompressed bytes.

        For brotlicffi, call finish(). For other implementations, attempt to
        process an empty bytes to finalize the stream.
        """
        if not self.seen_data:
            return b""
        try:
            if hasattr(self.decompressor, "finish"):
                # Only available in the 'brotlicffi' package.
                return self.decompressor.finish()
            # For other implementations, attempt to finalize by processing an empty
            # bytes object. This will typically return any remaining data.
            return self._decompress(b"")
        except brotli.error as exc:
            raise DecodingError(str(exc)) from exc